function removeDuplicateImgTags(str) { 
// 定义了一个名为 removeDuplicateImgTags 的函数，它接受一个字符串参数 str

var imgTags = str.split(/\n|\r/).filter(Boolean); 
// 将输入的字符串 str 按照换行符 \n 或回车符 \r 进行分割，得到一个字符串数组 imgTags
// 然后使用 filter(Boolean) 方法过滤掉空字符串元素

var uniqueImgTags = Array.from(new Set(imgTags)); 
// 通过创建一个 Set 数据结构来去除 imgTags 数组中的重复元素，并使用 Array.from 方法将其转换回数组 uniqueImgTags

return uniqueImgTags.join('\n'); 
// 将 uniqueImgTags 数组的元素用换行符 \n 连接成一个字符串并返回

}

