jsLib:
let default_pm = {
    appid: "qcbook",
    optype: "0",
    ostype: "0",
    package_name: "com.martian.qmbook",
    version_code: "617",
    version_name: "2.2.6.8"
};

function o2p(json) {
    if (typeof json !== "object" || json === null) {
        return "";
    }
    return Object.keys(json)
        .sort()
        .map(key => encodeURIComponent(key) + "=" + json[key])
        .join("&");
}

function ruid(l, k = true) {
    var u = String(Packages.java.util.UUID.randomUUID());
    u = k ? u : u.replace(/-/g, "");
    return l > 0 ? u.substring(0, l) : u;
}

function creatRequest(path, params, method, body) {
    const { source, java } = this;
    let default_pm = JSON.parse(source.getVariable());
    let pm = Object.assign({}, params, default_pm);
    let spm = o2p(pm);
    pm.sign = java.md5Encode(spm + "&key=qcbook_123456");
    spm = o2p(pm);
    return path + "?" + spm;
}

loginUrl:
function login() {
    let aid = ruid(16, false),
        did = ruid(),
        gaid = ruid(),
        t = Date.now().toString(),
        model = Packages.android.os.Build.MODEL,
        brand = Packages.android.os.Build.MANUFACTURER,
        os = Math.floor(Math.random() * (15 - 10 + 1)) + 10;
    default_pm.device_id = did;
    default_pm.gaid = gaid;
    default_pm.model = model;
    default_pm.brand = brand;
    default_pm.channel = brand;
    default_pm.osversion = os;
    default_pm.android_id = aid;
    pm = Object.assign({}, default_pm);
    pm.t = t;
    spm = o2p(pm) + "&key=qcbook_123456";
    sign = java.md5Encode(spm);
    pm.sign = sign;
    spm = o2p(pm);
    java.log(spm);
    u = "https://qcbook.taoyuewenhua.net/guest_user_login?" + spm;

    loginres = java.ajax(u);
    res = JSON.parse(loginres);
    if (res.errmsg == "success") {
        java.longToast("✅登录成功");
        default_pm.uid = res.data.uid;
        default_pm.token = res.data.token;
        source.setVariable(JSON.stringify(default_pm));
    } else {
        java.longToast("❌登录失败" + res.errmsg);
    }
}

