  java.log("未注册设备，自动注册中…");
  eval(String(source.loginUrl));
  login();
}
let push = (list, title, url, type) => list.push({ title: title, url: url, style: { layout_flexGrow: type } });

const categories = [
  [
    "玄幻", "奇幻", "武侠", "仙侠", "都市",
