];

let list = [];

// 男生推荐
push(list, "▱▱▱▱男生推荐▱▱▱▱", null, 1);
categories[0].forEach(category => {
  // 生成动态请求地址
  let u = `@js:let t = Date.now().toString();
  let params = {
    btype: 100,
    category: "${category}",
    ctype: 1,
    page: page - 1,
    pageSize: "16",
    t: t
  };
  creatRequest("/book_mall/book_rank", params)`;
  push(list, category, u, 0.16);
});

// 女生推荐
