function getVariable(id) {
  const {source} = this;
  var arr = ["&filter_word=0","&filter_up_status=0","&filter_is_paid=0","&filter_uptime=0"];
  try {
    arr = JSON.parse(source.getVariable());
  } catch(e) {
    source.setVariable(JSON.stringify(arr));
  }
  if (!id) return arr;
  return arr[id];
}
function Join() {
  return getVariable.call(this).join("");
}
