  source.setVariable(JSON.stringify(arr));
  java.toast("设置成功");
}
function filterPaid(id){
  arr[2] = "&filter_is_paid="+id;
  source.setVariable(JSON.stringify(arr));
  java.toast("设置成功");
}
function filterUptime(id){
  arr[3] = "&filter_uptime="+id;
  source.setVariable(JSON.stringify(arr));
  java.toast("设置成功");
}
function filterWord(id){
  arr[0] = "&filter_word="+id;
  source.setVariable(JSON.stringify(arr));
  java.toast("设置成功");
}
