  java.toast("设置成功");
}
function login() {
  cookie.removeCookie(source.key);
  java.startBrowser("https://wap.ciweimao.com/signup/login?redirect=https%3A%2F%2Fwap.ciweimao.com%2Freader%2Fmy_info","登录");
}

