var header = {"User-Agent":java.webViewUA,"Referer":baseUrl,"Cookie":cookie.getCookie(source.key),"Accept-Encoding":"gzip, deflate"};
if(/id="J_BookRead_WaterMark"/.test(result)){
var access_key = ajax("ajax_get_session_code",body,header).chapter_access_key;
var res = ajax("get_book_chapter_detail_info",body+"&chapter_access_key="+access_key,header);
decrypt({"content":res.chapter_content,"keys":res.encryt_keys,"accessKey":access_key}).replace(/<span>\w+<\/span>/g,"");
}
