@js:
const u = source.key, list = [];
const push = (title, url, flex) => list.push({title, url, style: {layout_flexGrow: 1, layout_flexBasisPercent: flex}});
const doc = org.jsoup.Jsoup.parse(java.ajax(u+"fenlei")).select('.fenlei a');
[
    ["排行榜", "paihang"],
    ["完结", "wanjie"],
    ["最新", "zuixin"]
].forEach(([a, b]) => {
    push(`・${a}・`, b + "<,/{{page}}.html>", 1);
    doc.forEach(e => 
      push(
        String(e.text()).split("(")[0],
        String(e.attr('href')).replace(/\/([^\/]+)\/$/, b != "zuixin" ? `${b}/$1<,-{{page}}>.html`: `$1/<,{{page}}.html>`),
        .25
    ));
});
JSON.stringify(list);

